// Extract JSON from Gemini response
const raw = $json.candidates[0].content.parts[0].text;
// Handle ```json ... ``` fences if present
let cleaned = raw.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
// Extract all individual JSON objects
const objects = [];
let depth = 0;
let start = -1;
for (let i = 0; i < cleaned.length; i++) {
  if (cleaned[i] === '{') {
    if (depth === 0) start = i;
    depth++;
  } else if (cleaned[i] === '}') {
    depth--;
    if (depth === 0 && start !== -1) {
      objects.push(cleaned.substring(start, i + 1));
      start = -1;
    }
  }
}
if (objects.length === 0) {
  throw new Error('Failed to extract JSON: ' + raw.substring(0, 200));
}
let parsed;
if (objects.length === 1) {
  parsed = JSON.parse(objects[0]);
} else {
  parsed = JSON.parse('[' + objects.join(',') + ']');
}
if (!Array.isArray(parsed)) {
  parsed = [parsed];
}
const results = parsed.map(item => {
  item.processed_at = new Date().toISOString();
  item.source_file = items[0].json?.fileName || '';
  item.original_file_id = items[0].json?.originalFileId || '';
  return { json: item };
});
return results;

